mapper.select:
SELECT log_id, equipment_id, equipment_code, equipment_name, change_type, old_value, new_value, change_reason, operator_name, create_time FROM dms_equipment_log
AND equipment_id = #{equipmentId} AND equipment_code LIKE CONCAT('%', #{equipmentCode}, '%') AND equipment_name LIKE CONCAT('%', #{equipmentName}, '%') AND change_type = #{changeType}
ORDER BY log_id DESC
